<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body{font-family:Arial,Helvetica,sans-serif;margin:20px;background:#f9f9f9;}
  h1{text-align:center;}
  form{margin-bottom:20px;display:flex;flex-wrap:wrap;gap:10px;}
  label{width:100%;}
  input[type="number"],input[type="date"],select,textarea{width:calc(100% - 12px);padding:5px;}
  #add-expense{width:auto;margin-top:5px;}
  #form-error{color:red;font-weight:bold;}
  table{width:100%;border-collapse:collapse;background:#fff;}
  th,td{text-align:left;padding:8px;border-bottom:1px solid #ddd;}
  .expense-row:hover{background:#f0f0f0;}
  .exp-del{color:white;background:#d9534f;border:none;padding:3px 6px;cursor:pointer;}
  .summary{margin-top:20px;}
  .cat-total{display:inline-block;margin-right:15px;}
</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<form id="expense-form">
  <label>
    Amount:
    <input type="number" step="0.01" id="amount" required>
  </label>
  <label>
    Category:
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>
    Date:
    <input type="date" id="date" required>
  </label>
  <label>
    Note:
    <textarea id="note"></textarea>
  </label>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<div class="filters">
  <label>
    Category Filter:
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>
    From:
    <input type="date" id="filter-from">
  </label>
  <label>
    To:
    <input type="date" id="filter-to">
  </label>
</div>

<table id="expense-table">
  <thead>
    <tr><th>Amount</th><th>Category</th><th>Date</th><th></th></tr>
  </thead>
  <tbody></tbody>
</table>

<div class="summary">
  Total: $<span id="total">0.00</span>
  <div id="cat-summaries"></div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'expenses';
  let expenses = [];

  // Load from localStorage
  function loadExpenses() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) expenses = JSON.parse(data);
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Render expense list and totals
  function render() {
    const tbody = document.querySelector('#expense-table tbody');
    tbody.innerHTML = '';
    const visible = getFilteredExpenses();
    visible.forEach(exp => {
      const tr = document.createElement('tr');
      tr.className = 'expense';
      tr.dataset.id = exp.id;
      tr.innerHTML = `
        <td>$${exp.amount.toFixed(2)}</td>
        <td>${capitalize(exp.category)}</td>
        <td>${exp.date}</td>
        <td><button class="exp-del">Delete</button></td>
      `;
      tbody.appendChild(tr);
    });
    updateTotals(visible);
  }

  // Capitalize first letter
  function capitalize(s){return s.charAt(0).toUpperCase()+s.slice(1);}

  // Get filtered expenses based on UI filters
  function getFilteredExpenses() {
    const catFilter = document.getElementById('filter-category').value;
    const fromDate = document.getElementById('filter-from').value;
    const toDate = document.getElementById('filter-to').value;

    return expenses.filter(exp => {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromDate && exp.date < fromDate) return false;
      if (toDate && exp.date > toDate) return false;
      return true;
    });
  }

  // Update total and per-category totals
  function updateTotals(visible) {
    const totalEl = document.getElementById('total');
    const catSummaries = document.getElementById('cat-summaries');
    let total = 0;
    const catMap = {};

    visible.forEach(exp => {
      total += exp.amount;
      catMap[exp.category] = (catMap[exp.category] || 0) + exp.amount;
    });

    totalEl.textContent = total.toFixed(2);

    // Render per-category totals
    catSummaries.innerHTML = '';
    ['groceries','transport','bills','fun'].forEach(cat => {
      const span = document.createElement('span');
      span.className = 'cat-total';
      span.dataset.cat = cat;
      span.textContent = `${capitalize(cat)}: $${(catMap[cat]||0).toFixed(2)}`;
      catSummaries.appendChild(span);
    });
  }

  // Add new expense
  function addExpense(e){
    e.preventDefault();
    const amountInput = document.getElementById('amount');
    const category = document.getElementById('category').value;
    const date = document.getElementById('date').value;
    const note = document.getElementById('note').value.trim();

    const formError = document.getElementById('form-error');
    const amountVal = parseFloat(amountInput.value);

    if (!amountInput.value || isNaN(amountVal) || amountVal <= 0 || !date) {
      formError.textContent = 'Please enter a valid, non‑zero amount and date.';
      return;
    }

    formError.textContent = '';
    const newExp = {
      id: Date.now().toString(),
      amount: amountVal,
      category,
      date,
      note
    };
    expenses.unshift(newExp);
    saveExpenses();
    render();
    amountInput.value = '';
  }

  // Delete expense
  function deleteExpense(e){
    if (!e.target.classList.contains('exp-del')) return;
    const tr = e.target.closest('.expense');
    const id = tr.dataset.id;
    expenses = expenses.filter(exp => exp.id !== id);
    saveExpenses();
    render();
  }

  // Attach event listeners
  document.getElementById('expense-form').addEventListener('submit', addExpense);
  document.querySelector('#expense-table tbody').addEventListener('click', deleteExpense);
  ['filter-category','filter-from','filter-to'].forEach(id=>{
    document.getElementById(id).addEventListener('change', render);
  });

  // Initial load
  loadExpenses();
  render();
})();
</script>
</body>
</html>
